package main

import (
	"math"
)

func solve(nums []int64, queries [][]int64) []int64 {
	ans := make([]int64, 0, len(queries))
	for _, query := range queries {
		li, ri, threshold := query[0], query[1], query[2]
		subarray := nums[li : ri+1]
		freq := make(map[int64]int64)
		for _, num := range subarray {
			freq[num]++
		}
		var candidates []int64
		for num, cnt := range freq {
			if cnt >= threshold {
				candidates = append(candidates, num)
			}
		}
		if len(candidates) == 0 {
			ans = append(ans, -1)
			continue
		}
		maxFreq := int64(0)
		for _, num := range candidates {
			if freq[num] > maxFreq {
				maxFreq = freq[num]
			}
		}
		var maxCandidates []int64
		for _, num := range candidates {
			if freq[num] == maxFreq {
				maxCandidates = append(maxCandidates, num)
			}
		}
		minNum := int64(math.MaxInt64)
		for _, num := range maxCandidates {
			if num < minNum {
				minNum = num
			}
		}
		ans = append(ans, minNum)
	}
	return ans
}
